#include "mix_kernels_cpu.h"

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

namespace {

constexpr int BLOCK_SIZE = 256;
constexpr long SAMPLE_THREADS_PER_OMP_THREAD = 256;
constexpr long WARMUP_SAMPLE_THREADS_PER_OMP_THREAD = 64;

struct half2 {
  std::uint16_t x;
  std::uint16_t y;
};

static_assert(sizeof(half2) == 4, "half2 must be 4 bytes");

static std::uint64_t g_sink = 0;

inline std::uint16_t float_to_half(float f) {
  std::uint32_t x;
  std::memcpy(&x, &f, sizeof(x));

  std::uint32_t sign = (x >> 16) & 0x8000u;
  std::uint32_t mantissa = x & 0x007fffffu;
  int exp = static_cast<int>((x >> 23) & 0xffu) - 127 + 15;

  if (exp <= 0) {
    if (exp < -10) {
      return static_cast<std::uint16_t>(sign);
    }
    mantissa = (mantissa | 0x00800000u) >> (1 - exp);
    if (mantissa & 0x00001000u) {
      mantissa += 0x00002000u;
    }
    return static_cast<std::uint16_t>(sign | (mantissa >> 13));
  }

  if (exp >= 31) {
    return static_cast<std::uint16_t>(sign | 0x7c00u);
  }

  if (mantissa & 0x00001000u) {
    mantissa += 0x00002000u;
    if (mantissa & 0x00800000u) {
      mantissa = 0;
      ++exp;
      if (exp >= 31) {
        return static_cast<std::uint16_t>(sign | 0x7c00u);
      }
    }
  }

  return static_cast<std::uint16_t>(sign | (static_cast<std::uint32_t>(exp) << 10) |
                                    (mantissa >> 13));
}

inline float half_to_float(std::uint16_t h) {
  std::uint32_t sign = (static_cast<std::uint32_t>(h & 0x8000u)) << 16;
  std::uint32_t exp = (h >> 10) & 0x1fu;
  std::uint32_t mantissa = h & 0x03ffu;
  std::uint32_t out = 0;

  if (exp == 0) {
    if (mantissa == 0) {
      out = sign;
    } else {
      int e = -14;
      while ((mantissa & 0x0400u) == 0) {
        mantissa <<= 1;
        --e;
      }
      mantissa &= 0x03ffu;
      out = sign | (static_cast<std::uint32_t>(e + 127) << 23) |
            (mantissa << 13);
    }
  } else if (exp == 31) {
    out = sign | 0x7f800000u | (mantissa << 13);
  } else {
    out = sign | ((exp + (127 - 15)) << 23) | (mantissa << 13);
  }

  float f;
  std::memcpy(&f, &out, sizeof(f));
  return f;
}

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <class T>
inline bool equal(const T a, const T b) {
  return a == b;
}

template <>
inline int mad(const int a, const int b, const int c) {
  return static_cast<int>(static_cast<std::int32_t>(
      static_cast<std::int64_t>(a) * static_cast<std::int64_t>(b) +
      static_cast<std::int64_t>(c)));
}

template <>
inline short mad(const short a, const short b, const short c) {
  return static_cast<short>(static_cast<std::int16_t>(
      static_cast<int>(a) * static_cast<int>(b) + static_cast<int>(c)));
}

template <>
inline half2 conv_int(const int i) {
  const std::uint16_t h = float_to_half(static_cast<float>(i));
  return half2{h, h};
}

template <>
inline half2 mad(const half2 a, const half2 b, const half2 c) {
  return half2{float_to_half(half_to_float(a.x) * half_to_float(b.x) +
                             half_to_float(c.x)),
               float_to_half(half_to_float(a.y) * half_to_float(b.y) +
                             half_to_float(c.y))};
}

template <>
inline bool equal(const half2 a, const half2 b) {
  return a.x == b.x && a.y == b.y;
}

template <class T>
inline std::uint64_t raw_bits(const T& v) {
  std::uint64_t out = 0;
  std::memcpy(&out, &v, sizeof(T));
  return out;
}

template <>
inline std::uint64_t raw_bits(const half2& v) {
  return static_cast<std::uint64_t>(v.x) |
         (static_cast<std::uint64_t>(v.y) << 16);
}

template <class T>
void benchmark_func_cpu(T seed, T* g_data, long size, int total_blocks,
                        int compute_iterations, long sample_total_threads) {
  const long total_threads = static_cast<long>(total_blocks) * BLOCK_SIZE;
  const long active_threads = std::min(total_threads, sample_total_threads);
  const long big_stride = total_threads * ELEMENTS_PER_THREAD;

#pragma omp parallel
  {
    std::uint64_t local_acc = 0;

#pragma omp for schedule(static)
    for (long tid = 0; tid < active_threads; ++tid) {
      const long block_idx = tid / BLOCK_SIZE;
      const long thread_idx = tid % BLOCK_SIZE;
      const long idx =
          block_idx * BLOCK_SIZE * ELEMENTS_PER_THREAD + thread_idx;

      T tmps[ELEMENTS_PER_THREAD];
      for (int k = 0; k < FUSION_DEGREE; ++k) {
        for (int j = 0; j < ELEMENTS_PER_THREAD; ++j) {
          const long access_idx = idx + j * BLOCK_SIZE + k * big_stride;
          if (access_idx < size) {
            tmps[j] = g_data[access_idx];
          } else {
            tmps[j] = conv_int<T>(0);
          }

          for (int i = 0; i < compute_iterations; ++i) {
            tmps[j] = mad(tmps[j], tmps[j], seed);
          }
        }

        T sum = conv_int<T>(0);
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
          sum = mad(tmps[j], tmps[j + 1], sum);
        }

        local_acc ^= raw_bits(sum) + 0x9e3779b97f4a7c15ULL +
                     (local_acc << 6) + (local_acc >> 2);

        if (equal(sum, conv_int<T>(-1))) {
          const long write_idx = idx + k * big_stride;
          if (write_idx < size) {
            g_data[write_idx] = sum;
          }
        }
      }
    }

#pragma omp critical
    { g_sink ^= local_acc; }
  }
}

inline float time_ms(const std::function<void()>& fn) {
  const auto start = std::chrono::high_resolution_clock::now();
  fn();
  const auto stop = std::chrono::high_resolution_clock::now();
  float ms =
      std::chrono::duration<float, std::milli>(stop - start).count();
  if (ms <= 0.0f) ms = 1.0e-6f;
  return ms;
}

void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int total_reduced_blocks =
      static_cast<int>(reduced_grid_size / BLOCK_SIZE);
  const long sample_threads = std::min(
      static_cast<long>(total_reduced_blocks) * BLOCK_SIZE,
      WARMUP_SAMPLE_THREADS_PER_OMP_THREAD *
          static_cast<long>(std::max(1, omp_get_max_threads())));
  benchmark_func_cpu<short>((short)1, reinterpret_cast<short*>(cd), size,
                            total_reduced_blocks, 0, sample_threads);
}

void runbench(double* cd, long size, bool doHalfs, int compute_iterations) {
  const long compute_grid_size =
      size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const int total_blocks = static_cast<int>(compute_grid_size / BLOCK_SIZE);
  const long long computations =
      (ELEMENTS_PER_THREAD * (long long)compute_grid_size +
       (2LL * ELEMENTS_PER_THREAD * compute_iterations) *
           (long long)compute_grid_size) *
      FUSION_DEGREE;
  const long long memoryoperations = size;
  const long sample_threads = std::min(
      static_cast<long>(total_blocks) * BLOCK_SIZE,
      SAMPLE_THREADS_PER_OMP_THREAD *
          static_cast<long>(std::max(1, omp_get_max_threads())));

  const float kernel_time_mad_sp = time_ms([&] {
    benchmark_func_cpu<float>(1.0f, reinterpret_cast<float*>(cd), size,
                              total_blocks, compute_iterations, sample_threads);
  });

  const float kernel_time_mad_dp = time_ms([&] {
    benchmark_func_cpu<double>(1.0, cd, size, total_blocks, compute_iterations,
                               sample_threads);
  });

  float kernel_time_mad_hp = 0.0f;
  if (doHalfs) {
    const half2 h_ones = conv_int<half2>(1);
    kernel_time_mad_hp = time_ms([&] {
      benchmark_func_cpu<half2>(h_ones, reinterpret_cast<half2*>(cd), size,
                                total_blocks, compute_iterations,
                                sample_threads);
    });
  } else {
    kernel_time_mad_hp = 1.0e-6f;
  }

  const float kernel_time_mad_int = time_ms([&] {
    benchmark_func_cpu<int>(1, reinterpret_cast<int*>(cd), size, total_blocks,
                            compute_iterations, sample_threads);
  });

  std::printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000.0 /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000.0 /
          (1000.0 * 1000.0 * 1000.0),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000.0 /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000.0 /
          (1000.0 * 1000.0 * 1000.0),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000.0 /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000.0 /
          (1000.0 * 1000.0 * 1000.0),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000.0 /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000.0 /
          (1000.0 * 1000.0 * 1000.0));
}

}  // namespace

